import React, { useState, useEffect, useRef } from "react";
import "../styles/GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?",
      emotion: "🤍 Support",
    },
  ]);
  const [input, setInput] = useState("");
  const [typing, setTyping] = useState(false);

  const chatEndRef = useRef(null);

  // Auto-scroll to bottom
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, typing]);

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = {
      sender: "user",
      text: input,
      emotion: "💭 You",
    };

    setMessages((prev) => [...prev, userMessage]);
    setInput("");
    setTyping(true);

    // Fake AI reply (replace later with backend)
    setTimeout(() => {
      const botReply = {
        sender: "bot",
        text: "I hear you. That sounds really difficult. Do you want to tell me more about what’s been making you feel this way? 💜",
        emotion: "🧠 Empathy",
      };

      setMessages((prev) => [...prev, botReply]);
      setTyping(false);
    }, 1500);
  };

  return (
    <div className="chat-page">
      <h2 className="chat-title">General Chat</h2>

      <div className="chat-container">
        <div className="chat-messages">
          {messages.map((msg, index) => (
            <div key={index} className={`msg ${msg.sender}`}>
              <span className="emotion-tag">{msg.emotion}</span>
              <p>{msg.text}</p>
            </div>
          ))}

          {typing && (
            <div className="msg bot typing">
              <span></span>
              <span></span>
              <span></span>
            </div>
          )}

          <div ref={chatEndRef}></div>
        </div>

        <div className="chat-input">
          <input
            type="text"
            placeholder="Type how you feel..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleSend()}
          />
          <button onClick={handleSend}>Send</button>
        </div>
      </div>
    </div>
  );
};

export default GeneralChat;
